// ── Recebe e valida payload do MT5 ──────────────
const body = $input.first().json.body ?? $input.first().json;

const ticker        = body.ticker        ?? '';
const signal        = body.signal        ?? '';
const currentPrice  = body.current_price ?? 0;
const askPrice      = body.ask_price     ?? 0;
const ma9Value      = body.ma_value     ?? 0;
const ma9Prev       = body.ma_prev      ?? 0;
const distancePct   = body.distance_pct  ?? 0;
const maPeriod      = body.ma_period     ?? 9;
const timeframe     = body.timeframe     ?? 'D1';
const serverTime    = body.server_time   ?? '';
const localTime     = body.local_time    ?? '';

if (!ticker || !signal || !currentPrice || !ma9Value) {
  throw new Error(`Payload inválido: ${JSON.stringify(body)}`);
}

// ── Monta objeto para o Supabase ─────────────────
const now = new Date().toISOString();

// data_indicators — bloco principal de indicadores
const data_indicators = {
  ma9: {
    value:        ma9Value,
    prev:         ma9Prev,
    period:       maPeriod,
    timeframe:    timeframe,
    applied:      'close'
  },
  price: {
    bid:          currentPrice,
    ask:          askPrice,
    vs_ma9:       signal,           // 'ABOVE' | 'BELOW'
    distance_pct: distancePct
  },
  meta: {
    server_time:  serverTime,
    local_time:   localTime,
    sent_at:      now
  }
};

// M9 boolean — true se preço ACIMA da MA9
//const m9 = (signal === 'BUY' ? 'UP' : 'DOWN');

return [{
  json: {
    ticker,
    signal,
    m9: signal,
    data_indicators,
    update_at: now.split('T')[0],   // apenas a data (YYYY-MM-DD)
    created_at: now
  }
}];

// Merge seguro: preserva todas as chaves existentes em data_mt5
// e atualiza apenas as chaves deste indicador
const getResult = $input.first().json;
const row = Array.isArray(getResult) ? getResult[0] : getResult;

const currentDataMt5 = (row && row.data_mt5) ? row.data_mt5 : {};

const data_indicators = $('Transformar Dados').item.json.data_indicators;
const m9              = $('Transformar Dados').item.json.m9;
const ticker          = $('Transformar Dados').item.json.ticker;
const signal          = $('Transformar Dados').item.json.signal;

const mergedDataMt5 = {
  ...currentDataMt5,
  ...data_indicators,
  m9_signal: m9
};

return [{
  json: {
    ticker,
    signal,
    m9,
    data_indicators,
    mergedDataMt5
  }
}];
